import{_ as n,o as t,c as o,a3 as r}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"69A. Industry Ohs Working Group","description":"","frontmatter":{"title":"69A. Industry Ohs Working Group","eba":"Mental Health Services 2024-2028","topics":["ohs","workers-comp"]},"headers":[],"relativePath":"ebas/mental-health/common-terms/ohs/69A-industry-ohs-working-group.md","filePath":"ebas/mental-health/common-terms/ohs/69A-industry-ohs-working-group.md"}'),i={name:"ebas/mental-health/common-terms/ohs/69A-industry-ohs-working-group.md"};function a(s,e,p,c,l,d){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="_69a-industry-ohs-working-group" tabindex="-1">69A. Industry Ohs Working Group <a class="header-anchor" href="#_69a-industry-ohs-working-group" aria-label="Permalink to &quot;69A. Industry Ohs Working Group&quot;">​</a></h1><p><strong>(a)</strong> The Employers (and their representative), the Employees and the Unions will proactively cooperate in development and recommendation of measures to improve occupational health and safety (OHS) outcomes, with the intent of improving Employee health and safety, preventing injury, illness and incapacity (and hence workers compensation payments), and supporting effective and responsive return to work, with a particular focus on the following:</p><p><strong>(i)</strong> safe patient and manual handling processes</p><p><strong>(ii)</strong> safe rostering practices and prevention of fatigue risks</p><p><strong>(iii)</strong> occupational violence and aggression prevention programs</p><p><strong>(iv)</strong> education for Managers/Supervisors regarding management of Employees</p><p><strong>(v)</strong> workplace bullying; and</p><p><strong>(vi)</strong> psychological injury.</p><p><strong>(b)</strong> The proactive cooperation described at clause 69A(a) with respect to the priorities identified above, will seek to achieve the following:</p><p><strong>(i)</strong> In the case of safe patient and manual handling processes, reduction of musculoskeletal injuries by identifying requirements for safe patient and manual handling programs including recommendation of principles and practices to prevent and reduce the associated risks</p><p><strong>(ii)</strong> the case of safe rostering practices, identification of staff and consumer safety risks associated with working hours, shift work, rostering practices and fatigue, including any preventable hazards; and recommendation of principles and practices to prevent and reduce the associated risks</p><p><strong>(iii)</strong> In the case of occupational violence and aggression prevention programs, ensuring the prevention and/or appropriate management of occupational violence to reduce associated injuries and illness, including the long-term mental health implications of exposure to continuing violence and aggression, including recommendation of principles and practices to prevent and reduce the associated risks, consistent with the Occupational Violence Principles, and making recommendations to address these</p><p><strong>(iv)</strong> In the case Education and training of Managers/Supervisors, appropriate understanding of management obligations in relation to occupational health and safety, workers compensation and return to work by identifying gaps and making recommendations to address these, and</p><p><strong>(v)</strong> In the case of workplace bullying, identification of bullying prevention principles and practices, including education on early identification and intervention, appropriate workplace behaviour/Code of Conduct and appropriate investigation and feedback processes, and making recommendations to implement these.</p><p><strong>(vi)</strong> in the case of psychological injuries, a shared approach to: <strong>(A)</strong> addressing work related causes of psychological injury, including bullying, OVA (including gendered violence) and burnout; and <strong>(B)</strong> finding available positions for an Employee with a psychological injury, including but not limited to positions with an alternate Employer by agreement where the Employee’s treating practitioner determines that it is unlikely that the Employee could return to work with their Employer, but could return to work with an alternate Employer. In the first instance, the primary focus will be with respect to work-related psychological injuries.</p><p><strong>(c)</strong> As these matters are relevant to all Employees and Employers covered by this Agreement, an Industry OHS Working Group will be established consisting of no more than three representatives from each of the following:</p><p><strong>(i)</strong> ANMF</p><p><strong>(ii)</strong> HACSU</p><p><strong>(iii)</strong> VHIA</p><p><strong>(iv)</strong> Department; and</p><p><strong>(v)</strong> other attendees as agreed by members of the working party.</p><p><strong>(d)</strong> In the case of ANMF, HACSU and VHIA, a representative may include a member.</p><p><strong>(e)</strong> The Industry OHS Working Group will commence meeting within three (3) months of the commencement of the Agreement and will meet bi-monthly or otherwise by agreement between its members.</p><p><strong>(f)</strong> The Industry OHS Working Group will determine any actions it will undertake, in addition to the above priorities</p><p><strong>(g)</strong> The Industry OHS Working Group will operate with the oversight of the MHIIC and will produce annual reports to be provided to all parties on the progress, actions and recommendations resulting from the Group’s work, with the first report to be delivered to the MHIIC no more than 12 months after the first meeting.</p>',25)])])}const m=n(i,[["render",a]]);export{h as __pageData,m as default};
